c
bool dequeue(Queue *Q, int *p_val) {
while (true) {
Node *h = Q->head;
Node *t = Q->tail;
Node *next = h->next;
if (h == Q->head) {           // Are h, t, next consistent?
if (h == t) {             // Is queue empty or tail falling behind?
if (next == NULL) return false; // Logically empty
CAS(&Q->tail, t, next); // Tail fell behind; help advance it
} else {
*p_val = next->value; // Read value BEFORE CAS
if (CAS(&Q->head, h, next)) {
free_node(h);     // Linearization Point
return true;
}
}
}
}
}
